  "q2_onscreen_people_location_and_action": {
    "visual_location": "健一家住宅客厅内靠近玄关入口的一侧，能看到入户门、空荡客厅、窗边窗帘、沙发和客厅桌的位置",
    "spatial_relations": "首帧画面侧取健一家室内客厅入口侧，不是酒店、酒店大门、案发套房或警方封锁现场。若画面出现门，它是健一家住宅入户门／玄关门，健一从该门进入自家室内；推门进入是动作过程，不把visual_location写成从门外到客厅的跨度。客厅内无人，窗帘在窗边被风吹动；一杯凉透的咖啡初始放在沙发前的客厅桌面上，健一坐下后才端起。没有电话、屏幕、照片、门内外偷听关系或房间内外声音关系。",
    "onscreen_people": [
      {
        "name": "田中健一（KENICHI_MAIN）",
        "position": "首帧位于自家入户门内侧或玄关与客厅连接处，面向空荡客厅；随后移动到客厅沙发前。",
        "first_frame_action": "刚推开家门进入，视线落向空荡荡的客厅，风吹动窗帘，桌上的咖啡杯在室内可见。",
        "video_process_action": "进入客厅后脱下外套，走到沙发坐下，从客厅桌上端起一只盛有凉透深褐咖啡的白色陶瓷杯，疲惫地抿一口；动作安静、克制，不与任何人互动。",
        "speaking_or_mouth_state": "不说话；嘴部闭合或在喝咖啡时自然动作，没有对白口型。"
      }
    ],
    "first_frame_ground_truth": "健一家客厅入口侧，家门刚被推开，田中健一独自进入，空荡客厅里只有窗边窗帘被风轻轻吹动，沙发前桌上放着一杯凉透的咖啡。"
  },
